#!/usr/bin/env python3
"""Write manifest/admission sidecars for a complete FLUX KNOT.

This is the local, zero-paid companion to `encode-knot.py` for FLUX.1-dev and
FLUX.1-schnell. It validates the KNOT header, component policy, required tensor
families, and shape metadata, then writes:

  <knot>.manifest.json
  <knot>.admission.json
"""

from __future__ import annotations

import argparse
import hashlib
import json
import struct
from pathlib import Path
from typing import Any


EXPECTED_INCLUDED = ["transformer", "vae", "text_encoder", "text_encoder_2"]
EXPECTED_SKIPPED = ["tokenizer", "tokenizer_2", "scheduler", "feature_extractor"]
COMPONENT_PREFIXES = {
    "transformer": ("flux_img_in_", "flux_dbl_", "flux_sgl_"),
    "vae": ("flux_vae_",),
    "text_encoder": ("flux_clip_",),
    "text_encoder_2": ("flux_t5_",),
}
COMPONENT_POLICY = "flux-with-vae-text-encoders"


def read_knot_header(path: Path) -> tuple[int, dict[str, Any]]:
    with path.open("rb") as handle:
        if handle.read(4) != b"KNOT":
            raise SystemExit(f"{path}: bad KNOT magic")
        version = struct.unpack("<H", handle.read(2))[0]
        metadata_len = struct.unpack("<I", handle.read(4))[0]
        metadata = json.loads(handle.read(metadata_len))
    return version, metadata


def sha256_file(path: Path) -> str:
    digest = hashlib.sha256()
    with path.open("rb") as handle:
        for chunk in iter(lambda: handle.read(64 * 1024 * 1024), b""):
            digest.update(chunk)
    return digest.hexdigest()


def validate_flux_metadata(metadata: dict[str, Any]) -> tuple[dict[str, int], dict[str, int]]:
    components = metadata.get("components") or {}
    tensors = metadata.get("tensors") or {}
    problems: list[str] = []

    if metadata.get("config", {}).get("arch") != "flux":
        problems.append("config.arch is not flux")
    if components.get("policy") != COMPONENT_POLICY:
        problems.append(f"components.policy is not {COMPONENT_POLICY}")

    included = set(components.get("included") or [])
    skipped = set(components.get("skipped") or [])
    for item in EXPECTED_INCLUDED:
        if item not in included:
            problems.append(f"components.included missing {item}")
    for item in EXPECTED_SKIPPED:
        if item not in skipped:
            problems.append(f"components.skipped missing {item}")

    tensor_counts = {
        component: sum(
            1
            for name in tensors
            if any(name.startswith(prefix) for prefix in prefixes)
        )
        for component, prefixes in COMPONENT_PREFIXES.items()
    }
    shape_counts = {
        component: sum(
            1
            for name, info in tensors.items()
            if any(name.startswith(prefix) for prefix in prefixes)
            and isinstance(info, dict)
            and isinstance(info.get("shape"), list)
            and len(info["shape"]) > 0
        )
        for component, prefixes in COMPONENT_PREFIXES.items()
    }
    for component, count in tensor_counts.items():
        if count <= 0:
            problems.append(f"missing {component} tensors")
        if count != shape_counts[component]:
            problems.append(
                f"{component} tensors missing shape metadata: "
                f"{count - shape_counts[component]} of {count}"
            )

    if problems:
        for problem in problems:
            print(f"  - {problem}")
        raise SystemExit("invalid FLUX KNOT")
    return tensor_counts, shape_counts


def main() -> None:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--knot", required=True, type=Path)
    parser.add_argument("--model-id", required=True)
    parser.add_argument("--source-hf", required=True)
    parser.add_argument("--artifact", required=True)
    args = parser.parse_args()

    if not args.knot.exists():
        raise SystemExit(f"missing KNOT: {args.knot}")

    version, metadata = read_knot_header(args.knot)
    tensor_counts, shape_counts = validate_flux_metadata(metadata)
    components = metadata.get("components") or {}
    manifest = {
        "model_id": args.model_id,
        "source_hf": args.source_hf,
        "artifact": args.artifact,
        "format": "knot/v1",
        "version": version,
        "arch": "flux",
        "components": components,
        "tensor_counts": tensor_counts,
        "shape_counts": shape_counts,
        "shape_metadata": True,
        "size": args.knot.stat().st_size,
        "sha256": sha256_file(args.knot),
    }
    admission = {
        **manifest,
        "status": "shape-admitted",
        "admission_level": "artifact-shape-only",
        "admission_source": "knot-header",
        "visible_image_admitted": False,
        "smoke_test_artifact": False,
        "missing": [],
    }

    manifest_path = args.knot.with_suffix(args.knot.suffix + ".manifest.json")
    admission_path = args.knot.with_suffix(args.knot.suffix + ".admission.json")
    manifest_path.write_text(json.dumps(manifest, indent=2) + "\n")
    admission_path.write_text(json.dumps(admission, indent=2) + "\n")
    print(json.dumps({"manifest": str(manifest_path), "admission": str(admission_path)}, indent=2))


if __name__ == "__main__":
    main()
